        // Check where clause
        result.Value.where.Should().Contain($"[{DBOperadorGruposAgendaDicInfo.PTabelaNome}].[{DBOperadorGruposAgendaDicInfo.Visto}] = @{DBOperadorGruposAgendaDicInfo.Visto}");
